def md(x):
    return '' if x is None else str(x).replace('|','\\|').replace('\n','<br>')
def provsum(items):
    items=items or []
    return 'attempts={}; success={}; unavailable={}; request_error={}; low_signal={}; circuit_open={}'.format(len(items),sum(1 for a in items if a.get('status')=='success'),sum(1 for a in items if a.get('status')=='unavailable'),sum(1 for a in items if a.get('status')=='request_error'),sum(1 for a in items if a.get('status')=='low_signal'),sum(1 for a in items if a.get('circuit_open')))
def qpath(trace,max_items=6):
    qs=[]
    for it in trace or []:
        if it.get('event') in ('search_executed','search_cache_hit') and it.get('query'):
            kind='cache' if it['event']=='search_cache_hit' else 'search'
            qs.append(f"{kind}: {it['query']} ({it.get('result_count')})")
    if not qs: return 'none'
    shown=qs[:max_items]
    txt='<br>'.join(md(q) for q in shown)
    return txt if len(qs)<=max_items else txt+f"<br>... (+{len(qs)-max_items} more)"
def tevents(trace,max_items=6):
    keep={'job_started','load_context','admission_gate','chapter_activity_validation','website_strategy','candidate_selected','official_domain_verified'}
    ev=[]
    for it in trace or []:
        e=it.get('event')
        if e in keep:
            s=e
            if 'status' in it: s+=f": {it['status']}"
            if 'stage' in it: s+=f": {it['stage']}"
            if 'target' in it: s+=f": {it['target']}"
            if 'decision' in it: s+=f": {it['decision']}"
            ev.append(s)
    if not ev: return 'none'
    shown=ev[:max_items]
    txt='<br>'.join(md(e) for e in shown)
    return txt if len(ev)<=max_items else txt+f"<br>... (+{len(ev)-max_items} more)"
def add_table(lines,title,intro,headers,rows):
    lines.append(f'## {title}\n')
    if intro: lines.append(intro+'\n')
    lines.append('| '+' | '.join(headers)+' |')
    lines.append('| '+' | '.join(['---']*len(headers))+' |')
    for r in rows: lines.append('| '+' | '.join(md(x) for x in r)+' |')
    lines.append('')
